// ==================== Composant Liste des commandes (Premier système) ====================
const OrderList = ({ orders, onUpdateOrderStatus, onModalOpenChange }) => {
  const [selectedGroupId, setSelectedGroupId] = useState(null);
  const containerRef = useRef(null);
  const [showScrollButton, setShowScrollButton] = useState(false);

  useEffect(() => {
    if (onModalOpenChange) {
      onModalOpenChange(!!selectedGroupId);
    }
  }, [selectedGroupId, onModalOpenChange]);

  const orderGroups = useMemo(() => {
    const groups = {};
    orders.forEach(order => {
      // ✅ التعديل: إضافة tableId إلى المفتاح
      const key = `${order.name}_${order.price}_${order.tableId}`;
      if (!groups[key]) {
        groups[key] = {
          id: key,
          name: order.name,
          price: order.price,
          quantity: 0,
          orders: [],
          status: order.status,
          tableId: order.tableId
        };
      }
      groups[key].quantity++;
      groups[key].orders.push(order);
      if (order.status === 'cancelled') groups[key].status = 'cancelled';
      else if (order.status === 'completed') groups[key].status = 'completed';
      else groups[key].status = 'pending';
    });
    return Object.values(groups);
  }, [orders]);

  useEffect(() => {
    if (containerRef.current && !selectedGroupId) {
      containerRef.current.scrollTop = containerRef.current.scrollHeight;
    }
  }, [orders, selectedGroupId]);

  const handleScroll = () => {
    if (containerRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = containerRef.current;
      setShowScrollButton(scrollHeight - scrollTop > clientHeight + 50);
    }
  };

  const scrollToTop = () => {
    if (containerRef.current) {
      containerRef.current.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  return (
    <>
      <div className="order-list-container" style={{ width: '95%', maxWidth: '800px', margin: '20px auto' }}>
        <div className="order-list-header">
          <h3 className="order-list-title">
            📋 Liste des commandes
            <span className="order-count-badge">{orders.length}</span>
          </h3>
          <div className="header-actions">
            <button className="refresh-btn" onClick={() => window.location.reload()}>🔄</button>
          </div>
        </div>
        
        <div ref={containerRef} className="order-list-scroll" onScroll={handleScroll} style={{ maxHeight: '500px', overflowY: 'auto' }}>
          {orderGroups.length === 0 ? (
            <div className="empty-orders">
              <div className="empty-icon">🍽️</div>
              <p>Aucune commande pour le moment</p>
            </div>
          ) : (
            orderGroups.map((group) => (
              <div key={group.id} className={`order-item ${group.status} animate-slide-up`}>
                <div className="order-item-content">
                  <div className="order-info" onClick={() => setSelectedGroupId(selectedGroupId === group.id ? null : group.id)} style={{ cursor: 'pointer', flex: 1 }}>
                    <span className="order-icon">🍽️</span>
                    <div className="order-details">
                      <div className="order-name">{group.name}</div>
                      <div className="order-meta">
                        <span className="order-price">{group.price} DA</span>
                        {group.quantity > 1 && <span className="order-quantity-badge">×{group.quantity}</span>}
                        <span className="order-table-badge" style={{ background: 'rgba(34,197,94,0.2)', color: '#22c55e', padding: '0px 6px', borderRadius: '10px', fontSize: '0.7rem', fontWeight: 'bold', marginLeft: '5px' }}>🍽️ Table {group.tableId}</span>
                      </div>
                    </div>
                  </div>
                  <div className="order-actions">
                    <div className={`order-status ${group.status}`}>
                      {group.status === 'pending' ? '⏳' : group.status === 'completed' ? '✅' : '❌'}
                    </div>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
        
        {showScrollButton && <button className="scroll-to-top" onClick={scrollToTop}>↑</button>}
      </div>
      
      {selectedGroupId && (
        <GroupDetailModal 
          groupId={selectedGroupId}
          orders={orders}
          onUpdateOrderStatus={onUpdateOrderStatus}
          onClose={() => setSelectedGroupId(null)} 
        />
      )}
    </>
  );
};

// ==================== Composant Liste des tables (Deuxième système) ====================
const TablesList = ({ completedOrders, onTableClick }) => {
  const [showScrollButton, setShowScrollButton] = useState(false);
  const containerRef = useRef(null);

  // تجميع الطلبات المكتملة حسب الطاولة والمنتج
  const tableGroups = useMemo(() => {
    const groups = {};
    
    completedOrders.forEach(order => {
      const tableId = order.tableId;
      if (!tableId) return;
      
      // ✅ نفس التعديل: إضافة tableId إلى المفتاح
      const productKey = `${tableId}_${order.name}_${order.price}`;
      
      if (!groups[productKey]) {
        groups[productKey] = {
          id: productKey,
          tableNumber: tableId,
          name: order.name,
          price: order.price,
          quantity: 0,
          orders: [],
          total: 0
        };
      }
      
      groups[productKey].quantity++;
      groups[productKey].orders.push(order);
      groups[productKey].total += order.price;
    });
    
    // تجميع النتائج حسب الطاولة
    const tablesMap = {};
    Object.values(groups).forEach(group => {
      const tableId = group.tableNumber;
      if (!tablesMap[tableId]) {
        tablesMap[tableId] = {
          id: tableId,
          tableNumber: tableId,
          items: [],
          total: 0,
          orderCount: 0
        };
      }
      tablesMap[tableId].items.push(group);
      tablesMap[tableId].total += group.total;
      tablesMap[tableId].orderCount += group.quantity;
    });
    
    return Object.values(tablesMap);
  }, [completedOrders]);

  const handleScroll = () => {
    if (containerRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = containerRef.current;
      setShowScrollButton(scrollHeight - scrollTop > clientHeight + 50);
    }
  };

  const scrollToTop = () => {
    if (containerRef.current) {
      containerRef.current.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  if (tableGroups.length === 0) {
    return (
      <div className="order-list-container" style={{ width: '95%', maxWidth: '800px', margin: '20px auto' }}>
        <div className="order-list-header">
          <h3 className="order-list-title">🍽️ Liste des tables <span className="order-count-badge">0</span></h3>
        </div>
        <div className="empty-orders"><div className="empty-icon">🍽️</div><p>Aucune table pour le moment</p><p className="empty-sub">Les tables apparaîtront ici lorsque les commandes seront livrées</p></div>
      </div>
    );
  }

  return (
    <div className="order-list-container" style={{ width: '95%', maxWidth: '800px', margin: '20px auto' }}>
      <div className="order-list-header">
        <h3 className="order-list-title">🍽️ Liste des tables <span className="order-count-badge">{tableGroups.length}</span></h3>
      </div>
      <div ref={containerRef} className="order-list-scroll" onScroll={handleScroll} style={{ maxHeight: '500px', overflowY: 'auto' }}>
        {tableGroups.map((table) => (
          <div key={table.id} className="order-item" style={{ borderLeftColor: '#f59e0b' }}>
            <div className="order-item-content">
              <div className="order-info" onClick={() => onTableClick(table.id)} style={{ cursor: 'pointer', flex: 1 }}>
                <span className="order-icon">🍽️</span>
                <div className="order-details">
                  <div className="order-name">Table N° {table.tableNumber}</div>
                  <div className="order-meta">
                    <span className="order-price">{table.orderCount} commande(s)</span>
                    <span className="order-table-badge" style={{ background: 'rgba(245,158,11,0.2)', color: '#f59e0b' }}>
                      💰 {table.total} DA
                    </span>
                  </div>
                  <div className="order-items-details" style={{ marginTop: '5px' }}>
                    {table.items.map((item, idx) => (
                      <div key={idx} className="order-item-detail" style={{ fontSize: '11px', color: '#22c55e', display: 'inline-block', marginRight: '10px' }}>
                        {item.name} {item.quantity > 1 && `×${item.quantity}`}
                      </div>
                    ))}
                  </div>
                </div>
              </div>
              <div className="order-actions">
                <div className="order-price" style={{ fontSize: '14px', fontWeight: 'bold' }}>{table.total} DA</div>
              </div>
            </div>
          </div>
        ))}
      </div>
      {showScrollButton && <button className="scroll-to-top" onClick={scrollToTop}>↑</button>}
    </div>
  );
};

// ==================== Composant de modification du CV ====================
const EditCVModal = ({ workerInfo, onSave, onClose }) => {
  const [editedInfo, setEditedInfo] = useState({ ...workerInfo });
  const [newSkill, setNewSkill] = useState("");

  const addSkill = () => {
    if (newSkill.trim() && !editedInfo.skills.includes(newSkill.trim())) {
      setEditedInfo({ ...editedInfo, skills: [...editedInfo.skills, newSkill.trim()] });
      setNewSkill("");
    }
  };

  const removeSkill = (skillToRemove) => {
    setEditedInfo({ ...editedInfo, skills: editedInfo.skills.filter(skill => skill !== skillToRemove) });
  };

  const handleSave = () => {
    onSave(editedInfo);
    onClose();
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '600px' }}>
        <button onClick={onClose} className="close-btn">✕</button>
        <div className="text-center"><div className="text-5xl mb-4">✏️</div><h2 className="text-2xl font-bold text-white mb-4">Modifier le CV</h2></div>
        <div className="edit-cv-form">
          <div className="mb-4"><label className="text-white text-sm block mb-2">👤 Nom complet</label><input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.name} onChange={(e) => setEditedInfo({...editedInfo, name: e.target.value})} /></div>
          <div className="mb-4"><label className="text-white text-sm block mb-2">💼 Titre du poste</label><input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.role} onChange={(e) => setEditedInfo({...editedInfo, role: e.target.value})} /></div>
          <div className="mb-4"><label className="text-white text-sm block mb-2">📧 Email</label><input type="email" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.email} onChange={(e) => setEditedInfo({...editedInfo, email: e.target.value})} /></div>
          <div className="mb-4"><label className="text-white text-sm block mb-2">📱 Téléphone</label><input type="tel" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.phone} onChange={(e) => setEditedInfo({...editedInfo, phone: e.target.value})} /></div>
          <div className="mb-4"><label className="text-white text-sm block mb-2">📍 Localisation</label><input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.location} onChange={(e) => setEditedInfo({...editedInfo, location: e.target.value})} /></div>
          <div className="mb-4"><label className="text-white text-sm block mb-2">📝 Bio</label><textarea className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" rows="3" value={editedInfo.bio} onChange={(e) => setEditedInfo({...editedInfo, bio: e.target.value})} /></div>
          <div className="mb-4"><label className="text-white text-sm block mb-2">💪 Compétences</label><div className="flex flex-wrap gap-2 mb-2">{editedInfo.skills.map((skill, i) => (<span key={i} className="skill-tag" style={{ display: 'inline-flex', alignItems: 'center', gap: '5px' }}>{skill}<button onClick={() => removeSkill(skill)} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '14px' }}>✕</button></span>))}</div><div className="flex gap-2"><input type="text" className="flex-1 p-2 rounded-xl bg-white/10 text-white border border-green-500/30" placeholder="Ajouter une compétence" value={newSkill} onChange={(e) => setNewSkill(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && addSkill()} /><button onClick={addSkill} className="btn-primary">+ Ajouter</button></div></div>
          <button onClick={handleSave} className="btn-primary w-full mt-4">💾 Enregistrer les modifications</button>
        </div>
      </div>
    </div>
  );
};

