    .profile-hero-section { position: relative; background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b, #0f0c29, #1a1a4a); background-size: 400% 400%; animation: gradientShift 12s ease infinite; min-height: 100vh; padding-top: 80px; }
    .order-list-container { position: relative; width: 95% !important; max-width: 800px !important; margin: 20px auto !important; background: rgba(0, 0, 0, 0.85); backdrop-filter: blur(20px); border-radius: 20px; border: 1px solid rgba(34, 197, 94, 0.3); box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5), 0 0 20px rgba(34, 197, 94, 0.2); transition: all 0.3s ease; }
    .order-list-header { display: flex; justify-content: space-between; align-items: center; padding: 15px 20px; background: linear-gradient(135deg, rgba(34, 197, 94, 0.2), rgba(34, 197, 94, 0.05)); border-radius: 20px 20px 0 0; border-bottom: 1px solid rgba(34, 197, 94, 0.3); }
    .order-list-title { color: white; font-size: 1.1rem; font-weight: bold; margin: 0; display: flex; align-items: center; gap: 8px; }
    .order-count-badge { background: #22c55e; color: white; border-radius: 20px; padding: 2px 8px; font-size: 0.75rem; font-weight: bold; }
